257	    noData = true;
258	    noFilteredData = true;
259	    render(<ProtectedApplicationsListPage />);
260	
261	    expect(NoDataMessage).toHaveBeenCalledTimes(1);
262	    expect(EmptyRowMessage).toHaveBeenCalledTimes(0);
263	  });
264	
265	  it('"EmptyRowMessage" FC is rendered when applications are found but filtered data is empty', async () => {
