286	    const discoveredApps = 'ACM discovered applications';
287	    const managedApps = 'ACM managed applications';
288	
289	    expect(screen.getByText(buttonTitle)).toBeInTheDocument();
290	    await user.click(screen.getByText(buttonTitle));
291	    expect(screen.getByText(discoveredApps)).toBeInTheDocument();
292	    expect(screen.getByText(managedApps)).toBeInTheDocument();
293	    await user.click(screen.getByText(buttonTitle));
294	    await waitFor(() => {
295	      expect(screen.queryByText(discoveredApps)).not.toBeVisible();
296	    });
297	    await waitFor(() => {
298	      expect(screen.queryByText(managedApps)).not.toBeInTheDocument();
299	    });
300	
301	    expect(screen.getByText(popoverTitle)).toBeInTheDocument();
302	    expect(screen.getByText(popoverTitle)).toBeEnabled();
303	  });
304	});
