320	    expect(screen.getAllByText('DR Status').length).toBeGreaterThan(0);
321	    expect(screen.getByText('Policy')).toBeInTheDocument();
322	    expect(screen.getByText('Cluster')).toBeInTheDocument();
323	  });
324	
325	  it('"Relocated DRPC" table row contains all required columns', async () => {
326	    filterDRPC = failingDRPCName;
327	    const { container } = render(<ProtectedApplicationsListPage />);
328	
329	    const expandButton = container.querySelector(
330	      '[data-test="expand-button"]'
331	    ) as HTMLElement;
332	    expect(expandButton).toBeInTheDocument();
333	
334	    expect(() => screen.getByText(failingDRPCName)).toThrow(unableToFindError);
335	    const nameElement = container.querySelector(
336	      '[data-label="Name"]'
337	    ) as HTMLElement;
338	    expect(nameElement).not.toBeNull();
339	    expect(nameElement).toHaveTextContent(relocatedDRPCName);
340	    expect(
341	      nameElement.querySelector(
342	        `[data-test='resource-link-${relocatedDRPCName}']`
343	      )
344	    ).toHaveAttribute(
345	      'to',
346	      `/k8s/ns/${relocatedDRPC.metadata.namespace}/ramendr.openshift.io~v1alpha1~DRPlacementControl/${relocatedDRPCName}`
347	    );
348	
349	    const policyElement = container.querySelector(
350	      '[data-label="Policy"]'
351	    ) as HTMLElement;
352	    expect(policyElement).not.toBeNull();
353	    expect(policyElement).toHaveTextContent(drPolicyName);
354	    expect(
355	      policyElement.querySelector(`[data-test='link-${drPolicyName}']`)
356	    ).toHaveAttribute('to', `${DR_BASE_ROUTE}/policies?name=${drPolicyName}`);
357	
358	    expect(container.querySelector('[data-label="Cluster"]')).toHaveTextContent(
359	      deploymentClusterName
360	    );
361	
362	    const kebabButton = screen.getByRole('button', { name: /Kebab toggle/i });
363	    await user.click(kebabButton);
364	    expect(screen.getByText('Edit configuration')).toBeVisible();
365	    expect(screen.getByText('Failover')).toBeVisible();
366	    expect(screen.getByText('Relocate')).toBeVisible();
367	  });
368	
369	  it('"FailingOver DRPC" expands to show namespaces when expand button is clicked', async () => {
370	    filterDRPC = relocatedDRPCName;
371	    const { container } = render(<ProtectedApplicationsListPage />);
372	
373	    expect(() => screen.getByText(relocatedDRPCName)).toThrow(
374	      unableToFindError
375	    );
376	    const nameElement = container.querySelector(
377	      '[data-label="Name"]'
378	    ) as HTMLElement;
379	    expect(nameElement).toHaveTextContent(failingDRPCName);
380	    expect(
381	      nameElement.querySelector(
382	        `[data-test='resource-link-${failingDRPCName}']`
383	      )
384	    ).toHaveAttribute(
385	      'to',
386	      `/k8s/ns/${failingDRPC.metadata.namespace}/ramendr.openshift.io~v1alpha1~DRPlacementControl/${failingDRPCName}`
387	    );
388	
389	    const expandButton = container.querySelector(
390	      '[data-test="expand-button"] button'
391	    ) as HTMLElement;
392	    expect(expandButton).toBeInTheDocument();
393	
394	    await user.click(expandButton);
395	
396	    expect(screen.getByText(namespaces[0])).toBeInTheDocument();
397	    expect(screen.getByText(namespaces[1])).toBeInTheDocument();
398	    expect(screen.getByText(namespaces[2])).toBeInTheDocument();
399	    expect(screen.getByText(namespaces[3])).toBeInTheDocument();
400	  });
401	});

